story1_2_similarity = cos_similarity(story1_tfidf, story2_tfidf)
print(f"第一个故事与第二个故事的余弦相似度: {story1_2_similarity:.4f}")

# 测试3：《A Scandal in Bohemia》与其他故事的相似度分析
